/* ── Particles ─────────────────────────────────────────────────── */
function Particles() {
  const ref = useRef(null);
  useEffect(() => {
    const cv = ref.current; if (!cv) return;
    const ctx = cv.getContext("2d");
    let W = cv.width = window.innerWidth, H = cv.height = window.innerHeight;
    const pts = Array.from({ length: 50 }, () => ({
      x: Math.random()*W, y: Math.random()*H,
      vx: (Math.random()-.5)*.28, vy: (Math.random()-.5)*.28,
      r: Math.random()*.9+.3, o: Math.random()*.4+.1,
    }));
    let raf;
    const draw = () => {
      ctx.clearRect(0,0,W,H);
      pts.forEach(p => {
        p.x+=p.vx; p.y+=p.vy;
        if(p.x<0)p.x=W; if(p.x>W)p.x=0; if(p.y<0)p.y=H; if(p.y>H)p.y=0;
        ctx.beginPath(); ctx.arc(p.x,p.y,p.r,0,Math.PI*2);
        ctx.fillStyle=`rgba(0,201,177,${p.o})`; ctx.fill();
      });
      for(let i=0;i<pts.length;i++) for(let j=i+1;j<pts.length;j++){
        const dx=pts[i].x-pts[j].x, dy=pts[i].y-pts[j].y, d=Math.sqrt(dx*dx+dy*dy);
        if(d<90){ ctx.beginPath(); ctx.moveTo(pts[i].x,pts[i].y); ctx.lineTo(pts[j].x,pts[j].y);
          ctx.strokeStyle=`rgba(77,217,232,${.07*(1-d/90)})`; ctx.lineWidth=.35; ctx.stroke(); }
      }
      raf=requestAnimationFrame(draw);
    };
    draw();
    const onR = () => { W=cv.width=window.innerWidth; H=cv.height=window.innerHeight; };
    window.addEventListener("resize", onR);
    return () => { cancelAnimationFrame(raf); window.removeEventListener("resize", onR); };
  }, []);
  return <canvas ref={ref} style={{ position:"fixed", inset:0, zIndex:0, pointerEvents:"none" }}/>;
}

/* ── Loader ────────────────────────────────────────────────────── */
function Loader({ onDone }) {
  const [pct, setPct] = useState(0);
  const [spark, setSpark] = useState(0);
  useEffect(() => {
    const t = setInterval(() => {
      setPct(p => { const n=p+2; if(n>=100){clearInterval(t);setTimeout(onDone,400);return 100;} return n; });
      setSpark(s => (s+1)%6);
    }, 28);
    return () => clearInterval(t);
  }, []);
  return (
    <div style={{ position:"fixed", inset:0, background:"#060810", zIndex:9999, display:"flex", flexDirection:"column", alignItems:"center", justifyContent:"center", gap:28 }}>
      <div style={{ position:"absolute", inset:0, backgroundImage:"linear-gradient(rgba(77,217,232,.05) 1px,transparent 1px),linear-gradient(90deg,rgba(77,217,232,.05) 1px,transparent 1px)", backgroundSize:"50px 50px" }}/>
      <div style={{ position:"relative", width:120, height:120, display:"flex", alignItems:"center", justifyContent:"center" }}>
        {[100,76,52].map((sz,i)=>(
          <div key={i} style={{ position:"absolute", width:sz, height:sz, borderRadius:"50%", border:`1px solid rgba(0,201,177,${.6-i*.15})`, animation:`lspin${i%2?"R":"F"} ${2.5+i*.8}s linear infinite`}}/>
        ))}
        {[0,60,120,180,240,300].map((deg,i)=>(
          <div key={i} style={{ position:"absolute", width:5, height:5, borderRadius:"50%", background:i===spark?C2:T, left:"50%", top:"50%", transform:`rotate(${deg}deg) translate(55px,-2.5px)`, opacity:i===spark?1:.2, boxShadow:i===spark?`0 0 8px ${C2}`:"none", transition:"all .15s"}}/>
        ))}
        <div style={{ zIndex:2, animation:"lbolt .8s ease-in-out infinite alternate", filter:`drop-shadow(0 0 12px ${T}) drop-shadow(0 0 24px ${C2})`}}>
          <Ic n="bolt" s={44} c={T}/>
        </div>
      </div>
      <div style={{ textAlign:"center" }}>
        <div style={{ fontFamily:"'Orbitron',monospace", fontSize:26, fontWeight:900, background:`linear-gradient(120deg,${C2},${T})`, WebkitBackgroundClip:"text", WebkitTextFillColor:"transparent", letterSpacing:4 }}>CADIFY</div>
        <div style={{ fontFamily:"'Orbitron',monospace", fontSize:10, letterSpacing:6, color:T, opacity:.7, marginTop:4 }}>INDIA PVT. LTD. · CONNECTED EVERYWHERE</div>
      </div>
      <div style={{ width:"min(280px,80vw)" }}>
        <div style={{ display:"flex", justifyContent:"space-between", marginBottom:8 }}>
          <span style={{ fontFamily:"'Exo 2',sans-serif", fontSize:10, color:"#8892b0", letterSpacing:2 }}>INITIALIZING</span>
          <span style={{ fontFamily:"'Orbitron',monospace", fontSize:10, color:T }}>{pct}%</span>
        </div>
        <div style={{ height:2, background:"rgba(77,217,232,.1)", borderRadius:2 }}>
          <div style={{ height:"100%", width:`${pct}%`, background:`linear-gradient(90deg,${T},${C2})`, boxShadow:`0 0 10px ${T}`, borderRadius:2, transition:"width .04s"}}/>
        </div>
      </div>
    </div>
  );
}

